import { SnapshotVersion } from '../core/snapshot_version';
import { RemoteTargetId, TargetId } from '../core/types';
import { TargetPurpose } from '../local/target_data';
import {
  documentKeySet,
  DocumentKeySet,
  mutableDocumentMap,
  MutableDocumentMap
