export type EvaluateResultType =
  | 'ERROR'
  | 'UNSET'
  | 'NULL'
  | 'BOOLEAN'
  | 'INT'
  | 'DOUBLE'
  | 'TIMESTAMP'
  | 'STRING'
  | 'BYTES'
  | 'REFERENCE'
  | 'GEO_POINT'
  | 'ARRAY'
  | 'MAP'
  | 'FIELD_REFERENCE'
  | 'VECTOR';

export class EvaluateResult {
  private constructor(
    readonly type: EvaluateResultType,
    readonly value?: Value
  ) {}

  static newError(): EvaluateResult {
    return new EvaluateResult('ERROR', undefined);
  }

  static newUnset(): EvaluateResult {
    return new EvaluateResult('UNSET', undefined);
  }

  static newNull(): EvaluateResult {
    return new EvaluateResult('NULL', MIN_VALUE);
  }

  static newValue(value: Value): EvaluateResult {
    if (isNullValue(value)) {
      return new EvaluateResult('NULL', MIN_VALUE);
    } else if (isBoolean(value)) {
      return new EvaluateResult('BOOLEAN', value);
    } else if (isInteger(value)) {
      return new EvaluateResult('INT', value);
    } else if (isDouble(value)) {
      return new EvaluateResult('DOUBLE', value);
    } else if (isTimestampValue(value)) {
      return new EvaluateResult('TIMESTAMP', value);
    } else if (isString(value)) {
      return new EvaluateResult('STRING', value);
    } else if (isBytes(value)) {
      return new EvaluateResult('BYTES', value);
    } else if (value.referenceValue) {
      return new EvaluateResult('REFERENCE', value);
    } else if (value.geoPointValue) {
      return new EvaluateResult('GEO_POINT', value);
    } else if (isArray(value)) {
      return new EvaluateResult('ARRAY', value);
    } else if (isVectorValue(value)) {
      // vector value must be before map value
      return new EvaluateResult('VECTOR', value);
    } else if (isMapValue(value)) {
      return new EvaluateResult('MAP', value);
    } else {
      return new EvaluateResult('ERROR', undefined);
    }
  }

  isErrorOrUnset(): boolean {
    return this.type === 'ERROR' || this.type === 'UNSET';
  }

  isNull(): boolean {
    return this.type === 'NULL';
  }
}

export function valueOrUndefined(value: EvaluateResult): Value | undefined {
  if (value.isErrorOrUnset()) {
    return undefined;
  }
  return value.value!;
}

export interface EvaluableExpr {
  evaluate(
    context: EvaluationContext,
    input: PipelineInputOutput
  ): EvaluateResult;
}

/**
 * @internal
 *
 * Unwraps a wrapped expression type, like BooleanExpression.
 *
 * @param expr The expression to unwrap.
 * @return The inner expression of a wrapped expression, otherwise
 * returns the input itself.
 */
export function unwrapExpression(expr: BooleanConstant): Constant;
export function unwrapExpression(
  expr: BooleanFunctionExpression
): FunctionExpression;
export function unwrapExpression(expr: BooleanField): Field;
export function unwrapExpression(expr: Expression): Expression;
export function unwrapExpression(expr: Expression): Expression {
  if (expr instanceof BooleanExpression) {
    return expr._expr;
  }

  return expr;
}

export function toEvaluable(expr: Expression): EvaluableExpr {
  expr = unwrapExpression(expr);

  if (expr instanceof Field) {
    return new CoreField(expr);
  } else if (expr instanceof Constant) {
    return new CoreConstant(expr);
  } else if (expr instanceof ListOfExprs) {
    return new CoreListOfExprs(expr);
  } else if (expr instanceof FunctionExpression) {
    // TODO(pipeline): We should define all supported function names as constants somewhere instead of magic strings.
    if (expr.name === 'add') {
      return new CoreAdd(expr);
    } else if (expr.name === 'subtract') {
      return new CoreSubtract(expr);
    } else if (expr.name === 'multiply') {
      return new CoreMultiply(expr);
    } else if (expr.name === 'divide') {
      return new CoreDivide(expr);
    } else if (expr.name === 'mod') {
      return new CoreMod(expr);
    } else if (expr.name === 'and') {
      return new CoreAnd(expr);
    } else if (expr.name === 'equal') {
      return new CoreEq(expr);
    } else if (expr.name === 'not_equal') {
      return new CoreNeq(expr);
    } else if (expr.name === 'less_than') {
      return new CoreLt(expr);
    } else if (expr.name === 'less_than_or_equal') {
      return new CoreLte(expr);
