import { ensureFirestoreConfigured, Firestore } from '../api/database';
import { AggregateImpl } from '../core/aggregate';
import { queryToAggregateTarget, queryToTarget } from '../core/query';
import {
  StructuredPipeline,
  StructuredPipelineOptions
} from '../core/structured_pipeline';
import { AggregateSpec } from '../lite-api/aggregate_types';
import { getDatastore } from '../lite-api/components';
import { Pipeline } from '../lite-api/pipeline';
import { Query } from '../lite-api/reference';
import {
  newUserDataReader,
  UserDataSource
} from '../lite-api/user_data_reader';
import { ExecutePipelineRequest as ProtoExecutePipelineRequest } from '../protos/firestore_proto_api';
import { Code, FirestoreError } from '../util/error';
import { cast } from '../util/input_validation';
import { mapToArray } from '../util/obj';

import {
  getEncodedDatabaseId,
  toQueryTarget,
  toRunAggregationQueryRequest
} from './serializer';

/**
 * @internal
 * @private
 *
 * This function is for internal use only.
 *
 * Returns the `QueryTarget` representation of the given query. Returns `null`
 * if the Firestore client associated with the given query has not been
 * initialized or has been terminated.
 *
 * @param query - The Query to convert to proto representation.
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function _internalQueryToProtoQueryTarget(query: Query): any {
  const firestore = cast(query.firestore, Firestore);
  const client = ensureFirestoreConfigured(firestore);
  const serializer = client._onlineComponents?.datastore.serializer;
  if (serializer === undefined) {
    return null;
  }
  return toQueryTarget(serializer!, queryToTarget(query._query)).queryTarget;
}

/**
 * @internal
 * @private
 *
 * This function is for internal use only.
 *
 * Returns `RunAggregationQueryRequest` which contains the proto representation
 * of the given aggregation query request. Returns null if the Firestore client
 * associated with the given query has not been initialized or has been
 * terminated.
 *
 * @param query - The Query to convert to proto representation.
 * @param aggregateSpec - The set of aggregations and their aliases.
 */
export function _internalAggregationQueryToProtoRunAggregationQueryRequest<
  AggregateSpecType extends AggregateSpec
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
>(query: Query, aggregateSpec: AggregateSpecType): any {
  const aggregates = mapToArray(aggregateSpec, (aggregate, alias) => {
    return new AggregateImpl(
      alias,
      aggregate.aggregateType,
      aggregate._internalFieldPath
    );
  });
  const firestore = cast(query.firestore, Firestore);
  const client = ensureFirestoreConfigured(firestore);
  const serializer = client._onlineComponents?.datastore.serializer;
  if (serializer === undefined) {
    return null;
  }

  return toRunAggregationQueryRequest(
    serializer!,
    queryToAggregateTarget(query._query),
    aggregates,
    /* skipAliasing= */ true
  ).request;
}

/**
 * @internal
 * @private
 *
 * This function is for internal use only.
 *
 * Returns the `ExecutePipelineRequest` representation of the given query.
 * Returns `null` if the Firestore client associated with the given query has
 * not been initialized or has been terminated.
 *
 * @param pipeline - The Pipeline to convert to proto representation.
 */
export function _internalPipelineToExecutePipelineRequestProto(
  pipeline: Pipeline
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
): any {
  if (!pipeline._db) {
    throw new FirestoreError(
      Code.FAILED_PRECONDITION,
      'This pipeline was created without a database and cannot be serialized for execution.'
    );
  }

  const firestore = cast(pipeline._db, Firestore);

  const userDataReader = newUserDataReader(firestore);
  const context = userDataReader.createContext(
    UserDataSource.Argument,
    '_internalPipelineToExecutePipelineRequestProto'
  );

  pipeline._readUserData(context);

  const datastore = getDatastore(firestore);
  const serializer = datastore.serializer;
  if (serializer === undefined) {
    return null;
  }

  const structuredPipeline = new StructuredPipeline(
    pipeline,
    new StructuredPipelineOptions()
  );
  const executePipelineRequest: ProtoExecutePipelineRequest = {
    database: getEncodedDatabaseId(serializer),
    structuredPipeline: structuredPipeline._toProto(serializer)
  };

  return executePipelineRequest;
}
